#include <stdio.h>
#include <stdlib.h>

int compare_desc(const void *a, const void *b) {
    long long x = *(const long long *)a;
    long long y = *(const long long *)b;
    return (y > x) - (y < x);
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, M;
        scanf("%lld %lld", &N, &M);
        long long *p = (long long *)malloc(N * sizeof(long long));
        for (int i = 0; i < N; ++i) scanf("%lld", &p[i]);
        qsort(p, N, sizeof(long long), compare_desc);
        long long sum = 0;
        long long ans = -1;
        for (int i = 0; i < N; ++i) {
            sum += p[i];
            if (sum >= M) { ans = i + 1; break; }
        }
        printf("%lld\n", ans);
        free(p);
    }
    return 0;
}

